+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7442,6 +7442,18 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
   // Return true if the loop contains any instructions that are not also part of
   // the VPlan or are skipped for VPlan-based cost computations. This indicates
   // that the VPlan contains extra simplifications.
+  // Check if the loop has reduction-like operations (and/or/xor) that might be
+  // optimized differently in VPlans.
+  bool HasReductionLikeOps = any_of(TheLoop->blocks(), [](BasicBlock *BB) {
+    return any_of(*BB, [](Instruction &I) {
+      unsigned Opc = I.getOpcode();
+      return Opc == Instruction::And || Opc == Instruction::Or ||
+             Opc == Instruction::Xor || Opc == Instruction::Add ||
+             Opc == Instruction::Mul || Opc == Instruction::FAdd ||
+             Opc == Instruction::FMul;
+    });
+  });
+
   return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx,
                                     TheLoop](BasicBlock *BB) {
     return any_of(*BB, [&SeenInstrs, &CostCtx, TheLoop, BB](Instruction &I) {
@@ -7449,7 +7461,7 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
         return false;
       return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
     });
-  });
+  }) || HasReductionLikeOps;
 }
 #endif

